function newId() { return "b" + Date.now() + Math.random().toString(36).slice(2,6); }

// ─── STORAGE HELPERS ────────────────────────────────────────────────────────
function loadBooks() {
  try {
    const raw = localStorage.getItem("ps_books");
    return raw ? JSON.parse(raw) : DEFAULT_BOOKS;
  } catch { return DEFAULT_BOOKS; }
}
function saveBooks(books) {
  try {
    localStorage.setItem("ps_books", JSON.stringify(books));
    return true;
  } catch { return false; }
}

// ─── ROOT ────────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("splash");
  const [splashDone, setSplashDone] = useState(false);
  const [selectedBook, setSelectedBook] = useState(null);
  const [books, setBooks] = useState(DEFAULT_BOOKS);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    const b = loadBooks();
    setBooks(b);
    setLoaded(true);
  }, []);

  const navigate = (p) => { setPage(p); window.scrollTo(0,0); };

  const handleSaveBooks = (newBooks) => {
    const ok = saveBooks(newBooks);
    if (ok) setBooks(newBooks);
    return ok;
  };

  if (!loaded) return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background: COLORS.parchment, fontFamily: FONTS.serif, fontSize:"1.1rem", color: COLORS.muted }}>
      Loading your library…
    </div>
  );

  const handleEnter = () => {
    setSplashDone(true);
    setTimeout(() => navigate("home"), 600);
  };

  return (
    <>
      <style>{GF}</style>
      {page === "splash" ? (
        <SplashPage onEnter={handleEnter} fading={splashDone} />
      ) : page === "bookdetail" && selectedBook ? (
        <BookDetail book={selectedBook} onBack={() => navigate("home")} />
      ) : page === "admin" ? (
        <AdminPage books={books} onSave={handleSaveBooks} onBack={() => navigate("home")} />
      ) : (
        <MainLayout page={page} navigate={navigate} books={books} onBookClick={(b) => { setSelectedBook(b); setPage("bookdetail"); window.scrollTo(0,0); }} />
      )}
    </>
  );
}

